import requests

class MCPClient:
    BASE_URL = "https://api.mcp.example.com"

    def get_live_data(self, endpoint):
        response = requests.get(f"{self.BASE_URL}/{endpoint}")
        response.raise_for_status()
        return response.json()

class TopcoderIntelligenceAssistant:
    def __init__(self, mcp_client):
        self.mcp_client = mcp_client

    def fetch_data(self, endpoint):
        return self.mcp_client.get_live_data(endpoint)

    def get_skills(self):
        skills_data = self.fetch_data("skills")
        return self.process_skills(skills_data)

    def process_skills(self, skills_data):
        # Assuming skills_data is a list of dictionaries
        return {skill['id']: skill['name'] for skill in skills_data}

# Example usage
if __name__ == "__main__":
    mcp_client = MCPClient()
    assistant = TopcoderIntelligenceAssistant(mcp_client)
    skills = assistant.get_skills()
    print(skills)
